3673	static int shouldPropagate(int target) {
3674	    if (!server.replication_allowed || target == PROPAGATE_NONE || server.loading)
3675	        return 0;
3676	
3677	    if (target & PROPAGATE_AOF) {
3678	        if (server.aof_state != AOF_OFF)
3679	            return 1;
3680	    }
3681	    if (target & PROPAGATE_REPL) {
3682	        if (server.masterhost == NULL && (server.repl_backlog || listLength(server.slaves) != 0 || asmMigrateInProgress()))
3683	            return 1;
3684	    }
3685	
3686	    return 0;
3687	}
3688	
3689	/* Propagate the specified command (in the context of the specified database id)
3690	 * to AOF and Slaves.
3691	 *
3692	 * flags are an xor between:
3693	 * + PROPAGATE_NONE (no propagation of command at all)
3694	 * + PROPAGATE_AOF (propagate into the AOF file if is enabled)
3695	 * + PROPAGATE_REPL (propagate into the replication link)
3696	 *
3697	 * This is an internal low-level function and should not be called!
3698	 *
3699	 * The API for propagating commands is alsoPropagate().
3700	 *
3701	 * dbid value of -1 is saved to indicate that the called do not want
3702	 * to replicate SELECT for this command (used for database neutral commands).
3703	 */
3704	static void propagateNow(int dbid, robj **argv, int argc, int target) {
3705	    if (!shouldPropagate(target))
3706	        return;
3707	
3708	    /* This needs to be unreachable since the dataset should be fixed during
3709	     * replica pause (otherwise data may be lost during a failover) */
3710	    serverAssert(!(isPausedActions(PAUSE_ACTION_REPLICA) &&
3711	                   (!server.client_pause_in_transaction)));
3712	
3713	    if (server.aof_state != AOF_OFF && target & PROPAGATE_AOF)
3714	        feedAppendOnlyFile(dbid,argv,argc);
3715	    if (target & PROPAGATE_REPL) {
3716	        replicationFeedSlaves(server.slaves,dbid,argv,argc);
3717	        asmFeedMigrationClient(argv, argc);
3718	    }
3719	}
3720	
3721	/* Used inside commands to schedule the propagation of additional commands
3722	 * after the current command is propagated to AOF / Replication.
3723	 *
3724	 * dbid is the database ID the command should be propagated into.
3725	 * Arguments of the command to propagate are passed as an array of redis
3726	 * objects pointers of len 'argc', using the 'argv' vector.
3727	 *
3728	 * The function does not take a reference to the passed 'argv' vector,
3729	 * so it is up to the caller to release the passed argv (but it is usually
3730	 * stack allocated).  The function automatically increments ref count of
3731	 * passed objects, so the caller does not need to. */
3732	void alsoPropagate(int dbid, robj **argv, int argc, int target) {
3733	    robj **argvcopy;
3734	    int j;
3735	
3736	    if (!shouldPropagate(target))
3737	        return;
3738	
